mapper.sql:
FROM org_node mn INNER JOIN org_node_closure c ON c.ancestor_id = mn.id INNER JOIN emp_employee_position p ON p.node_id = c.descendant_id AND p.status = 1 AND p.start_date <= CURDATE() AND (p.end_date IS NULL OR p.end_date >= CURDATE()) INNER JOIN emp_employee ee ON ee.id = p.employee_id INNER JOIN org_node n ON n.id = p.node_id LEFT JOIN org_grade g ON g.id = p.grade_id WHERE mn.manager_id = #{q.managerId} AND mn.status = 1 AND p.employee_id != #{q.managerId}
AND ee.status = #{q.status}
AND ee.status = 1
AND (ee.last_name LIKE CONCAT('%', #{q.keyword}, '%') OR ee.first_name LIKE CONCAT('%', #{q.keyword}, '%') OR ee.employee_code LIKE CONCAT('%', #{q.keyword}, '%'))
AND p.node_id = #{q.nodeId}
AND p.grade_id = #{q.gradeId}
